import{c as s,Q as e,j as n,m as t}from"./chunks/framework.iD28w_5a.js";const u=JSON.parse('{"title":"Stack Guard Page","description":"","frontmatter":{"title":"Stack Guard Page"},"headers":[],"relativePath":"notes/035/stack_guard_page_debug.md","filePath":"notes/035/stack_guard_page_debug.md","lastUpdated":1779686691000}'),i={name:"notes/035/stack_guard_page_debug.md"};function p(l,a,d,r,o,c){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="_035-stack-guard-page-排查日志" tabindex="-1">035 Stack Guard Page 排查日志 <a class="header-anchor" href="#_035-stack-guard-page-排查日志" aria-label="Permalink to &quot;035 Stack Guard Page 排查日志&quot;">​</a></h1><h2 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h2><p><code>test_multi_term_two_terminals_independent_pipes</code> 在 QEMU 中卡死，无任何串口输出。换成堆分配（<code>new</code>/<code>delete</code>）后正常通过，初步怀疑栈溢出。</p><h2 id="对象大小分析" tabindex="-1">对象大小分析 <a class="header-anchor" href="#对象大小分析" aria-label="Permalink to &quot;对象大小分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对象</th><th>成员大小</th><th>栈分配数量</th><th>小计</th></tr></thead><tbody><tr><td><code>TerminalCell</code></td><td>12B (<code>char</code> + pad + 2×<code>uint32_t</code>)</td><td>—</td><td>—</td></tr><tr><td><code>Terminal::screen_[ROWS][COLS]</code></td><td>80×25×12 = 24,000B</td><td>×2</td><td>~48KB</td></tr><tr><td><code>Pipe::buffer_[PIPE_BUFFER_SIZE]</code></td><td>4,096B</td><td>×4</td><td>~16KB</td></tr><tr><td><strong>合计</strong></td><td></td><td></td><td><strong>~64KB</strong></td></tr></tbody></table><p>内核栈大小：<code>STACK_PAGES = 4</code> → 16KB。溢出约 4 倍。</p><h2 id="根因定位" tabindex="-1">根因定位 <a class="header-anchor" href="#根因定位" aria-label="Permalink to &quot;根因定位&quot;">​</a></h2><p>Guard page 检测代码已存在于 <code>exception_handlers.cpp</code>（<code>handle_pf</code>），但从未被触发。排查发现两个原因：</p><h3 id="原因-1-guard-pages-从未被-unmap" tabindex="-1">原因 1：Guard pages 从未被 unmap <a class="header-anchor" href="#原因-1-guard-pages-从未被-unmap" aria-label="Permalink to &quot;原因 1：Guard pages 从未被 unmap&quot;">​</a></h3><ul><li><code>exception_handlers.cpp:224</code> 注释写着 &quot;guard region that was unmapped below <code>__kernel_end</code> at test startup&quot;</li><li>但 <code>main_test.cpp</code> 中<strong>没有任何 unmap 代码</strong></li><li>栈溢出写入的内存仍然 mapped → #PF 不触发 → 静默踩坏相邻内存</li></ul><h3 id="原因-2-pf-没有-ist-独立栈" tabindex="-1">原因 2：#PF 没有 IST（独立栈） <a class="header-anchor" href="#原因-2-pf-没有-ist-独立栈" aria-label="Permalink to &quot;原因 2：#PF 没有 IST（独立栈）&quot;">​</a></h3><ul><li><code>idt.cpp:109</code>：<code>#PF</code> 配置 <code>ist=0</code>（无独立栈）</li><li>只有 <code>#DF</code>（Double Fault）使用 <code>ist=1</code></li><li>当 #PF 触发时，CPU 往已溢出的栈 push 中断帧 → 再次 #PF → Double Fault → Triple Fault → QEMU 静默重启</li></ul><h3 id="原因-3-boot-stack-使用-2mb-huge-page-映射" tabindex="-1">原因 3：Boot stack 使用 2MB huge page 映射 <a class="header-anchor" href="#原因-3-boot-stack-使用-2mb-huge-page-映射" aria-label="Permalink to &quot;原因 3：Boot stack 使用 2MB huge page 映射&quot;">​</a></h3><ul><li>Mini kernel 通过 <code>identity_map_up_to()</code> 用 2MB huge page 映射所有物理内存</li><li><code>VMM::unmap()</code> 操作 4KB 粒度，无法直接 unmap 2MB huge page 中的单个 4KB 页</li><li>需要先 split 2MB page 为 512×4KB pages</li></ul><h2 id="修复方案-共-8-个文件" tabindex="-1">修复方案（共 8 个文件） <a class="header-anchor" href="#修复方案-共-8-个文件" aria-label="Permalink to &quot;修复方案（共 8 个文件）&quot;">​</a></h2><h3 id="_1-linker-script-—-添加-guard-区域" tabindex="-1">1. Linker script — 添加 guard 区域 <a class="header-anchor" href="#_1-linker-script-—-添加-guard-区域" aria-label="Permalink to &quot;1. Linker script — 添加 guard 区域&quot;">​</a></h3><p>在 <code>__kernel_end</code> 和 <code>.stack</code> 之间插入 64KB NOLOAD guard 区域：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>__kernel_end = .;</span></span>
<span class="line"><span>.boot_guard (NOLOAD) : ALIGN(4096) {</span></span>
<span class="line"><span>    __boot_guard_start = .;</span></span>
<span class="line"><span>    . = . + 0x10000;          /* 64 KB guard */</span></span>
<span class="line"><span>    __boot_guard_end = .;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>.stack (NOLOAD) : ALIGN(4096) {</span></span>
<span class="line"><span>    . = . + 0x4000;           /* 16 KB stack */</span></span>
<span class="line"><span>    __kernel_stack_top = .;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h3 id="_2-gdt-—-添加-ist2-栈" tabindex="-1">2. GDT — 添加 IST2 栈 <a class="header-anchor" href="#_2-gdt-—-添加-ist2-栈" aria-label="Permalink to &quot;2. GDT — 添加 IST2 栈&quot;">​</a></h3><p><code>gdt.hpp</code> 新增 <code>pf_stack_[4096]</code>，<code>gdt.cpp</code> 设置 <code>tss_.ist[1]</code> 指向栈顶。</p><h3 id="_3-idt-—-pf-使用-ist-2" tabindex="-1">3. IDT — #PF 使用 IST=2 <a class="header-anchor" href="#_3-idt-—-pf-使用-ist-2" aria-label="Permalink to &quot;3. IDT — #PF 使用 IST=2&quot;">​</a></h3><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ExceptionVector</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::PF, isr_pf_stub, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">IDTPrivilege</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::Kernel, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">IDTGateType</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::Interrupt, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_4-vmm-—-添加-split-2mb-page" tabindex="-1">4. VMM — 添加 split_2mb_page() <a class="header-anchor" href="#_4-vmm-—-添加-split-2mb-page" aria-label="Permalink to &quot;4. VMM — 添加 split_2mb_page()&quot;">​</a></h3><p>利用 <code>walk_level()</code> 已有的 huge page 自动拆分逻辑（<code>should_alloc=true</code> 时遇到 PS=1 的 entry 会分配新 PT 并展开为 512 个 4KB entry）。新方法只需 walk 到 PD 层即可触发拆分。</p><h3 id="_5-main-test-cpp-—-运行时-unmap-guard-pages" tabindex="-1">5. main_test.cpp — 运行时 unmap guard pages <a class="header-anchor" href="#_5-main-test-cpp-—-运行时-unmap-guard-pages" aria-label="Permalink to &quot;5. main_test.cpp — 运行时 unmap guard pages&quot;">​</a></h3><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">g_vmm.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">split_2mb_page</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(guard_start);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 2MB → 512×4KB</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (addr </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> guard_start; addr </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> guard_end; addr </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4096</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    g_vmm.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">unmap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(addr);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              // unmap guard pages</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="_6-exception-handlers-cpp-—-更新检测逻辑" tabindex="-1">6. exception_handlers.cpp — 更新检测逻辑 <a class="header-anchor" href="#_6-exception-handlers-cpp-—-更新检测逻辑" aria-label="Permalink to &quot;6. exception_handlers.cpp — 更新检测逻辑&quot;">​</a></h3><p>用 <code>__boot_guard_start</code> / <code>__boot_guard_end</code> 替代旧的 <code>__kernel_end</code> + <code>BOOT_GUARD_PAGES</code> 计算，直接检查 fault 地址是否落在 guard 范围内。</p><h2 id="验证结果" tabindex="-1">验证结果 <a class="header-anchor" href="#验证结果" aria-label="Permalink to &quot;验证结果&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BOOT STACK OVERFLOW DETECTED</span></span>
<span class="line"><span>  Fault address (CR2):  0xFFFFFFFF8108C148</span></span>
<span class="line"><span>  Guard page range:     [0xFFFFFFFF8107E000, 0xFFFFFFFF8108E000)</span></span>
<span class="line"><span>  Boot stack range:     [0xFFFFFFFF8108E000, 0xFFFFFFFF81092000)</span></span>
<span class="line"><span>  Current RSP:          0xFFFFFFFF8108C150</span></span>
<span class="line"><span>  RIP:                  0xFFFFFFFF81032D95</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Guard page 精准捕获。fault 地址在 guard 范围内，RSP 已越过栈底。</p><p>额外发现：首个触发的不是 035 的测试，而是 031 的 <code>test_terminal_construction</code>——单个 Terminal 栈分配（24KB screen buffer）就超过 16KB boot stack。</p><h2 id="关键教训" tabindex="-1">关键教训 <a class="header-anchor" href="#关键教训" aria-label="Permalink to &quot;关键教训&quot;">​</a></h2><ol><li><strong>注释说&quot;已 unmap&quot;不代表真的 unmap 了</strong>——代码和注释不一致是最难排查的问题</li><li><strong>#PF 必须配 IST</strong>：栈溢出场景下 #PF handler 不能用当前栈，否则直接 Double Fault</li><li><strong>2MB huge page 是隐形的 guard page 杀手</strong>：即使 linker 预留了空间，运行时 huge page 映射让整个区域都可访问</li></ol>`,34)])])}const g=s(i,[["render",p]]);export{u as __pageData,g as default};
